def detect_arbitrage(ticks):
    if len(ticks) < 2:
        return False

    threshold = 0.5
    last_symbol = None
    last_price = None
    volatility_sum = 0
    for i in range(1, len(ticks)):
        timestamp, symbol, price = ticks[i]
        if symbol != last_symbol:
            if last_symbol is not None:
                volatility_sum = 0
            last_symbol = symbol
            last_price = price
        else:
            volatility_sum += abs(price - last_price)
        if volatility_sum > threshold:
            return True
    return False

for data, expected in test_data + [new_test_case, heavy_noise_case, slow_move_case]:
    assert detect_arbitrage(data) == expected, f"Failed for {data}"

print("All tests passed!")
```
